Greedy insertion with incremental cost evaluation: attempt insertion into all feasible routes in parallel, select the one with minimum marginal cost increase, and if none feasible then create new assign.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    for idx := range oris {
        shipID := total_ship + idx
        bestIdx := -1
        bestCostIncrease := 1e9
        var tempCostBackup [MAXASSIGNS]float64

        // Try inserting into each existing assign
        for i := 0; i < dispatch.AssignsLen; i++ {
            originalCost := dispatch.Assigns[i].Cost
            if dispatch.Assigns[i].AddShip(shipID, oris[idx], dess[idx]) {
                dispatch.Assigns[i].GenRoute()
                if dispatch.Assigns[i].Cost >= 0 {
                    costIncrease := dispatch.Assigns[i].Cost - originalCost
                    tempCostBackup[i] = originalCost
                    if costIncrease < bestCostIncrease {
                        bestCostIncrease = costIncrease
                        bestIdx = i
                    }
                }
                // Rollback this trial
                dispatch.Assigns[i].RemoveShip(shipID)
                dispatch.Assigns[i].GenRoute()
            }
        }

        // Also try a potential new empty assign slot if within bounds
        if dispatch.AssignsLen < MAXASSIGNS && bestIdx == -1 {
            // Try creating a fresh route starting at origin station
            // We simulate by checking feasibility without permanently adding yet
            // Actually we must commit because it's a real fallback
            // We'll treat candidate as dispatch.Assigns[dispatch.AssignsLen]
            candIdx := dispatch.AssignsLen
            // Backup current state (likely zero/empty) – we'll just try insert
            if dispatch.Assigns[candIdx].AddShip(shipID, oris[idx], dess[idx]) {
                dispatch.Assigns[candIdx].GenRoute()
                if dispatch.Assigns[candIdx].Cost >= 0 {
                    bestIdx = candIdx
                    bestCostIncrease = 0 // New route has minimal base cost already
                } else {
                    // Cleanup failed trial
                    dispatch.Assigns[candIdx].RemoveShip(shipID)
                    dispatch.Assigns[candIdx].GenRoute()
                }
            }
        }

        // Commit the chosen insertion
        if bestIdx >= 0 {
            if bestIdx >= dispatch.AssignsLen {
                dispatch.AssignsLen++
            }
            // Ensure we haven't already added during fallback trial above
            // Re‑add to guarantee correct state after earlier rollbacks
            // First remove if already present from fallback trial (but we cleaned up)
            dispatch.Assigns[bestIdx].RemoveShip(shipID)
            ok := dispatch.Assigns[bestIdx].AddShip(shipID, oris[idx], dess[idx])
            if ok {
                dispatch.Assigns[bestIdx].GenRoute()
            }
        } else {
            // Absolute fallback: force create new assign even if previous trial failed?
            // But we already tried new assign above; if still failing, something's wrong.
            // For safety, still ensure we don't drop the order: retry with last resort approach.
            // Find first assign where removal might help? Not needed per spec—just ensure we process all orders.
            // Since spec says never stop outer loop, we simply note failure but continue.
            // Attempt once more with a brand‑new assign ignoring prior state pollution.
            if dispatch.AssignsLen < MAXASSIGNS {
                // Reset candidate assign to clean slate implicitly via RemoveShip on all IDs,
                // but we don't know which ships it contains. Safer to use next available empty slot.
                // Our dispatch.Assigns may contain stale data; we'll rely on AddShip internal checks.
                candIdx := dispatch.AssignsLen
                // Clear candidate entirely by removing all ships – but we lack iteration over ships.
                // Instead assume empty initially; AddShip will fail if constraints violated.
                dispatch.Assigns[candIdx].RemoveShip(shipID)
                ok := dispatch.Assigns[candIdx].AddShip(shipID, oris[idx], dess[idx])
                if ok {
                    dispatch.Assigns[candIdx].GenRoute()
                    dispatch.AssignsLen++
                }
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch

